TEST(reflog_read_parses_sha) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    ReflogEntry entries[32];
    size_t count = test_reflog_read(&repo, "HEAD", entries, 32);
    TEST_ASSERT_TRUE(count > 0);

    // Verify old_sha and new_sha are 40 hex characters
    TEST_ASSERT_EQ(strlen(entries[0].new_sha), 40);

    // Verify all characters are hex
    for (size_t i = 0; i < 40; i++) {
        char c = entries[0].new_sha[i];
        bool is_hex = (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f');
        TEST_ASSERT_TRUE(is_hex);
    }

    git_repo_close(&repo);
}

