TEST(reflog_append_basic) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Read current HEAD reflog count
    ReflogEntry entries_before[32];
    size_t count_before = test_reflog_read(&repo, "HEAD", entries_before, 32);

    // Append new entry (use repo.head_sha as the old_sha)
    bool result = test_reflog_append(&repo, "HEAD",
        repo.head_sha, "0123456789abcdef0123456789abcdef01234567",
        "Test User", "test@example.com", "test: Test message");

    TEST_ASSERT_TRUE(result);

    // Verify entry count increased
    ReflogEntry entries_after[32];
    size_t count_after = test_reflog_read(&repo, "HEAD", entries_after, 32);
    TEST_ASSERT_EQ(count_after, count_before + 1);

    // Verify new entry is at index 0 (newest)
    TEST_ASSERT_STREQ(entries_after[0].message, "test: Test message");

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

