TEST(reflog_rewrite_removes_entry) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // First, add a few entries to have something to remove
    test_reflog_append(&repo, "refs/heads/rewrite_test",
        nullptr, "1111111111111111111111111111111111111111",
        "Test User", "test@example.com", "entry 1");
    test_reflog_append(&repo, "refs/heads/rewrite_test",
        "1111111111111111111111111111111111111111", "2222222222222222222222222222222222222222",
        "Test User", "test@example.com", "entry 2");
    test_reflog_append(&repo, "refs/heads/rewrite_test",
        "2222222222222222222222222222222222222222", "3333333333333333333333333333333333333333",
        "Test User", "test@example.com", "entry 3");

    // Verify we have 3 entries
    ReflogEntry entries_before[32];
    size_t count_before = test_reflog_read(&repo, "refs/heads/rewrite_test", entries_before, 32);
    TEST_ASSERT_EQ(count_before, 3);

    // Remove the middle entry (index 1, which is "entry 2" in newest-first order)
    bool result = test_reflog_rewrite(&repo, "refs/heads/rewrite_test", 1);
    TEST_ASSERT_TRUE(result);

    // Verify count decreased
    ReflogEntry entries_after[32];
    size_t count_after = test_reflog_read(&repo, "refs/heads/rewrite_test", entries_after, 32);
    TEST_ASSERT_EQ(count_after, 2);

    // Verify entry 3 is still at index 0 and entry 1 is at index 1
    TEST_ASSERT_STREQ(entries_after[0].message, "entry 3");
    TEST_ASSERT_STREQ(entries_after[1].message, "entry 1");

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

