    test_reflog_append(&repo, "refs/heads/single_entry_test",
        nullptr, "abcdabcdabcdabcdabcdabcdabcdabcdabcdabcd",
        "Test User", "test@example.com", "only entry");

    // Verify we have 1 entry
    ReflogEntry entries[32];
    size_t count = test_reflog_read(&repo, "refs/heads/single_entry_test", entries, 32);
    TEST_ASSERT_EQ(count, 1);

    // Remove the only entry
    bool result = test_reflog_rewrite(&repo, "refs/heads/single_entry_test", 0);
